// src/pages/PatientLogin.jsx
import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Box,
  Alert,
  Grid,
} from "@mui/material";
import PersonIcon from "@mui/icons-material/Person";
import { useAuth } from "../context/AuthContext";

export default function PatientLogin() {
  const [isLogin, setIsLogin] = useState(true);
  const [form, setForm] = useState({
    fullName: "",
    email: "",
    password: "",
    confirmPassword: "",
  });
  const [error, setError] = useState("");

  const navigate = useNavigate();
  const { login } = useAuth();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError("");
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setError("");

    if (!isLogin) {
      // Register
      if (form.password !== form.confirmPassword) {
        setError("Passwords do not match");
        return;
      }
      if (form.password.length < 6) {
        setError("Password must be at least 6 characters");
        return;
      }

      const newUser = {
        id: Date.now(),
        fullName: form.fullName,
        email: form.email,
        password: form.password, // In real app, never store plain password
      };

      localStorage.setItem(
        "users",
        JSON.stringify([
          ...JSON.parse(localStorage.getItem("users") || "[]"),
          newUser,
        ]),
      );

      login(newUser);
      navigate("/");
    } else {
      // Login
      const users = JSON.parse(localStorage.getItem("users") || "[]");
      const foundUser = users.find(
        (u) => u.email === form.email && u.password === form.password,
      );

      if (foundUser) {
        login(foundUser);
        navigate("/");
      } else {
        setError("Invalid email or password");
      }
    }
  };

  return (
    <Container maxWidth="sm" sx={{ py: 10 }}>
      <Paper elevation={6} sx={{ p: 5, borderRadius: 4 }}>
        <Box sx={{ textAlign: "center", mb: 4 }}>
          <PersonIcon sx={{ fontSize: 60, color: "#1976d2" }} />
          <Typography variant="h4" fontWeight={700} sx={{ mt: 2 }}>
            {isLogin ? "Patient Login" : "Create Account"}
          </Typography>
          <Typography color="text.secondary">
            {isLogin ? "Sign in to book appointments" : "Join Arogya Nepal"}
          </Typography>
        </Box>

        {error && (
          <Alert severity="error" sx={{ mb: 3 }}>
            {error}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          {!isLogin && (
            <TextField
              fullWidth
              label="Full Name"
              name="fullName"
              value={form.fullName}
              onChange={handleChange}
              margin="normal"
              required
            />
          )}

          <TextField
            fullWidth
            label="Email Address"
            name="email"
            type="email"
            value={form.email}
            onChange={handleChange}
            margin="normal"
            required
          />

          <TextField
            fullWidth
            label="Password"
            name="password"
            type="password"
            value={form.password}
            onChange={handleChange}
            margin="normal"
            required
          />

          {!isLogin && (
            <TextField
              fullWidth
              label="Confirm Password"
              name="confirmPassword"
              type="password"
              value={form.confirmPassword}
              onChange={handleChange}
              margin="normal"
              required
            />
          )}

          <Button
            type="submit"
            fullWidth
            variant="contained"
            size="large"
            sx={{ mt: 4, py: 1.5, borderRadius: 3, fontWeight: 600 }}
          >
            {isLogin ? "Login" : "Register"}
          </Button>
        </form>

        <Box sx={{ mt: 3, textAlign: "center" }}>
          <Button
            onClick={() => setIsLogin(!isLogin)}
            sx={{ textTransform: "none" }}
          >
            {isLogin
              ? "Don't have an account? Register"
              : "Already have an account? Login"}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
